// Lee el total de coches de la pagina 1 y cuenta coches/pagina -> genera 1..N
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
let total = 0; const m = html.match(/([0-9.]+)\s*coches/i); if (m) total = parseInt(m[1].replace(/\./g,''),10) || 0;
const perPage = ([...html.matchAll(/data-analytics-vehicle-maker=/g)].length) || 12;
const pages = Math.min(Math.max(Math.ceil(total / perPage), 1), 200);
const out = []; for (let p = 1; p <= pages; p++) out.push({ json: { page: p } });
return out;

// Clicars - transform: HTML -> tarjetas (anchor data-analytics-vehicle-maker) -> UPSERT
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
function num(s){ const n=parseInt(String(s).replace(/[^0-9]/g,''),10); return isNaN(n)?null:n; }
function tagAttr(t,name){ const m=t.match(new RegExp(name+'="([^"]*)"','i')); return m?m[1]:''; }
function esc(v){ if(v===null||v===undefined) return 'NULL'; if(typeof v==='number') return isNaN(v)?'NULL':String(v); return "'"+String(v).replace(/'/g,"''")+"'"; }
function normFuel(s){ s=String(s).toLowerCase(); if(/gnc|glp|gas natural/.test(s)) return 'Gas'; if(/eléctric|electric/.test(s)) return 'Eléctrico'; if(/híbrid|hibrid/.test(s)) return 'Híbrido'; if(/diésel|diesel/.test(s)) return 'Diesel'; if(/gasolina/.test(s)) return 'Gasolina'; return ''; }
function normGear(s){ s=String(s).toLowerCase(); if(/autom/.test(s)) return 'Automatica'; if(/manual/.test(s)) return 'Manual'; return ''; }
const anchors = [...html.matchAll(/<a\b[^>]*data-analytics-vehicle-maker="[^"]*"[^>]*>/gi)];
const seen = new Set(); const rows = [];
for (let i=0;i<anchors.length;i++){
  const tag=anchors[i][0];
  const id=tagAttr(tag,'data-vehicle-web-id'); if(!id||seen.has(id)) continue; seen.add(id);
  const brand=tagAttr(tag,'data-analytics-vehicle-maker');
  const model=tagAttr(tag,'data-analytics-vehicle-model');
  const href=tagAttr(tag,'href'); const url=href.startsWith('http')?href:('https://www.clicars.com'+href);
  const start=anchors[i].index; const end=(i+1<anchors.length)?anchors[i+1].index:start+4000;
  const body=html.slice(start,end);
  const price=num(tagAttr(body,'data-price-web-offer'))||num(tagAttr(body,'data-price-web'));
  const img=(body.match(/<img[^>]+src="(https:\/\/storage[^"]+)"/i)||[])[1]||'';
  const text=body.replace(/<[^>]+>/g,' ').replace(/&amp;/g,'&').replace(/\s+/g,' ').trim();
  const year=(text.match(/\b(20\d{2}|19\d{2})\b/)||[])[1]||null;
  const km=num((text.match(/([0-9.]+)\s*km/i)||[])[1]);
  const cv=num((text.match(/(\d+)\s*CV/i)||[])[1]);
  const trans=normGear((text.match(/Manual|Autom[aá]tic[oa]/i)||[])[0]);
  const fuel=normFuel((text.match(/GNC|GLP|Di[eé]sel|Gasolina|El[eé]ctric[oa]|H[ií]brid[oa]/i)||[])[0]);
  let version='';
  if(brand&&model){ const vm=text.match(new RegExp(brand+'\\s+'+model.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'\\s+([^|0-9][^0-9]*?)\\s*(20\\d{2}|19\\d{2}|\\d[\\d.]*\\s*km)','i')); if(vm) version=vm[1].replace(/\s+/g,' ').trim().slice(0,80); }
  if(!price) continue;
  const title=(brand+' '+model+' '+version).replace(/\s+/g,' ').trim();
  const imagesJson=(img?JSON.stringify([img]):'[]').replace(/'/g,"''");
  const row='('+esc('clc_'+id)+", 'clicars', "+esc(url)+', '+esc(title)+', '+esc(brand)+', '+esc(model)+', '+esc(version)+', '+
    (year!=null?String(year):'NULL')+', '+(km!=null?String(km):'NULL')+', '+(price!=null?String(price):'NULL')+', '+
    esc(fuel)+', '+esc(trans)+', '+(cv!=null?String(cv):'NULL')+', '+esc(img)+", '"+imagesJson+"', 'profesional', 'compra', NOW(), NOW(), NOW())";
  rows.push(row);
}
if(!rows.length) return [{ json:{ sql:null, count:0 } }];
const cols='id, portal, url, title, brand, model, version, year, mileage, price, fuel, transmission, power_cv, image_url, images, seller_type, listing_type, first_seen_at, scraped_at, last_seen_at';
const onConflict="ON CONFLICT (id) DO UPDATE SET url=EXCLUDED.url, title=EXCLUDED.title, price=EXCLUDED.price, mileage=EXCLUDED.mileage, image_url=COALESCE(NULLIF(moveadvisor_market_offers.image_url,''), EXCLUDED.image_url), power_cv=COALESCE(EXCLUDED.power_cv, moveadvisor_market_offers.power_cv), last_seen_at=NOW(), updated_at=NOW()";
const sql='INSERT INTO moveadvisor_market_offers ('+cols+') VALUES '+rows.join(', ')+' '+onConflict;
return [{ json:{ sql:sql, count:rows.length } }];
